noncompliant:
#include <memory>

class S {
public:
    explicit S(int a, int b);
};

void g(std::shared_ptr<S> p1, std::shared_ptr<S> p2);

void f() {
    // Noncompliant: multiple allocations in one statement
    g(std::shared_ptr<S>(new S(1, 2)), std::shared_ptr<S>(new S(3, 4)));

    // Noncompliant: multiple new expressions
    auto result = process(new Data(), new Buffer(), new Context());
}

compliant:
#include <memory>

class S {
public:
    explicit S(int a, int b);
};

void g(std::shared_ptr<S> p1, std::shared_ptr<S> p2);

void f() {
    // Compliant: separate allocation statements
    auto p1 = std::shared_ptr<S>(new S(1, 2));
    auto p2 = std::shared_ptr<S>(new S(3, 4));
    g(p1, p2);

    // Better: use make_shared
    auto p3 = std::make_shared<S>(1, 2);
    auto p4 = std::make_shared<S>(3, 4);
    g(p3, p4);

    // Compliant: single allocation per statement
    auto data = std::make_unique<Data>();
    auto buffer = std::make_unique<Buffer>();
    auto context = std::make_unique<Context>();
    auto result = process(data.get(), buffer.get(), context.get());
}
